957	function makeStairVolumeMesh(
958	  stair: Extract<Element, { kind: 'stair' }>,
959	  elementsById: Record<string, Element>,
960	  paint: ViewportPaintBundle | null,
961	): THREE.Group {
962	  const group = new THREE.Group();
963	
964	  const sx = stair.runStartMm.xMm / 1000;
965	  const sz = stair.runStartMm.yMm / 1000;
966	  const ex = stair.runEndMm.xMm / 1000;
967	  const ez = stair.runEndMm.yMm / 1000;
968	  const dx = ex - sx;
969	  const dz = ez - sz;
970	  const runLen = Math.max(1e-3, Math.hypot(dx, dz));
971	  const stairWidth = THREE.MathUtils.clamp(stair.widthMm / 1000, 0.3, 4);
972	
973	  const baseLevelElev = elevationMForLevel(stair.baseLevelId, elementsById);
974	  const topLevelElev = elevationMForLevel(stair.topLevelId, elementsById);
975	  const totalRise = Math.max(Math.abs(topLevelElev - baseLevelElev), 0.1);
976	
977	  const riserCount = Math.max(
978	    Math.round((totalRise * 1000) / (stair.riserMm > 0 ? stair.riserMm : 175)),
979	    2,
980	  );
981	  const riserH = totalRise / riserCount;
982	  const treadDepth = runLen / riserCount;
983	  const treadThick = 0.04;
984	  const angle = Math.atan2(dz, dx);
985	
986	  const mat = new THREE.MeshStandardMaterial({
987	    color: categoryColorOr(paint, 'stair'),
988	    roughness: paint?.categories.stair.roughness ?? 0.85,
989	  });
990	
991	  const treadGeom = new THREE.BoxGeometry(treadDepth, treadThick, stairWidth);
992	  for (let i = 0; i < riserCount; i++) {
993	    const treadMesh = new THREE.Mesh(treadGeom, mat);
994	    const cx = sx + ((i + 0.5) / riserCount) * dx;
995	    const cz = sz + ((i + 0.5) / riserCount) * dz;
996	    // top surface of tread i sits at baseLevelElev + (i+1)*riserH
997	    const cy = baseLevelElev + (i + 1) * riserH - treadThick / 2;
998	    treadMesh.position.set(cx, cy, cz);
