    state = reduceShaft(state, { kind: 'click', pointMm: { xMm: 1000, yMm: 0 } }).state;
    state = reduceShaft(state, { kind: 'click', pointMm: { xMm: 1000, yMm: 1000 } }).state;
    expect(state.verticesMm).toHaveLength(3);
